---
import type { ImageMetadata } from "astro"
import { Image } from "astro:assets"

import { cn } from "@/lib/utils"
import {
  Avatar,
  AvatarFallback,
  AvatarGroup,
  AvatarImage,
} from "@/components/ui/avatar"
import { Button } from "@/components/ui/button"
import { Rating } from "@/components/ui/rating"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description: string
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  socialProof?: {
    avatars: {
      image?: ImageMetadata
      initials: string
      name?: string
    }[]
    rating: number
    text: string
  }
  image: {
    src: ImageMetadata
    alt: string
  }
}

const {
  class: className,
  title,
  description,
  buttons,
  socialProof,
  image,
} = Astro.props
---

<Section
  variant="floating"
  class={cn("dark bg-background overflow-hidden", className)}
>
  <Image
    src={image.src}
    alt={image.alt}
    class="absolute inset-0 size-full object-cover opacity-50"
    widths={[640, 960, 1280, 1536]}
    sizes="(min-width: 80rem) 80rem, 100vw"
  />
  <SectionContainer class="items-center text-center">
    <div class="flex max-w-2xl flex-col items-center gap-5">
      <h2
        class="text-foreground text-3xl leading-[1.1] font-semibold tracking-tight text-balance sm:text-4xl"
      >
        {title}
      </h2>
      <p class="text-muted-foreground text-lg leading-relaxed text-balance">
        {description}
      </p>
    </div>
    {
      buttons?.length && (
        <div class="flex flex-wrap justify-center gap-3">
          {buttons.map(({ href, label, ...button }, index) => (
            <Button
              as="a"
              href={href}
              size="lg"
              variant={button.variant ?? (index === 0 ? "default" : "outline")}
              {...button}
            >
              {label}
            </Button>
          ))}
        </div>
      )
    }
    {
      socialProof && (
        <div class="flex items-center gap-3">
          <AvatarGroup>
            {socialProof.avatars.map((avatar) => (
              <Avatar class="ring-background size-11 ring">
                <AvatarImage
                  src={avatar.image}
                  alt={avatar.name ?? avatar.initials}
                />
                <AvatarFallback>{avatar.initials}</AvatarFallback>
              </Avatar>
            ))}
          </AvatarGroup>
          <div class="flex flex-col gap-0.5">
            <Rating value={socialProof.rating} />
            <span class="text-muted-foreground text-sm">
              {socialProof.text}
            </span>
          </div>
        </div>
      )
    }
  </SectionContainer>
</Section>
